def best_kb_match(query: str) -> Tuple[str, float]:
    q = query.lower().strip()
    best_title, best_score = "Install software", 0.0
    for title, entry in KB.items():
        hay = " ".join([title] + entry.get("tags", []))
        score = SequenceMatcher(None, q, hay.lower()).ratio()
        if score > best_score:
            best_title, best_score = title, score
    return best_title, best_score


def classify_category(text: str) -> str:
    title, score = best_kb_match(text)
    return title if score >= 0.20 else "General help"


