def assistant_typing(delay_s: float = 0.20) -> None:
    with st.chat_message("assistant"):
        ph = st.empty()
        for dots in ["", ".", "..", "..."]:
            ph.markdown(f"Thinking{dots}")
            time.sleep(delay_s)
        ph.empty()


def kb_answer(title: str) -> str:
    steps = KB[title]["steps"]
    return "Try this:\n" + "\n".join([f"{i+1}. {s}" for i, s in enumerate(steps)])


def context_line() -> str:
    p = st.session_state.profile
    bits = []
    if p.get("device"):
        bits.append(f"Device: {p['device']}")
    if p.get("os"):
        bits.append(f"OS: {p['os']}")
    if p.get("location"):
        bits.append(f"Location: {p['location']}")
    return (" | ".join(bits)) if bits else ""


def run_quick_check(kind: str) -> List[str]:
    # A tiny “wizard” with progress for masters-level UX (still no external calls)
    checks: List[Tuple[str, float]] = []
    if kind == "VPN":
        checks = [("Checking internet reachability", 0.28), ("Checking VPN client status", 0.33), ("Checking common fixes", 0.39)]
    elif kind == "Wi‑Fi":
        checks = [("Checking adapter state", 0.30), ("Checking SSID / captive portal hints", 0.33), ("Checking quick remediations", 0.37)]
    elif kind == "Login":
        checks = [("Checking lockout pattern", 0.34), ("Checking MFA hints", 0.33), ("Checking safe next steps", 0.33)]
    else:
        checks = [("Checking basics", 0.40), ("Finding likely category", 0.30), ("Preparing next steps", 0.30)]

    notes: List[str] = []
    prog = st.progress(0, text="Running quick check…")
    acc = 0.0
    for label, w in checks:
        time.sleep(0.35)
        acc += w
        prog.progress(min(int(acc * 100), 100), text=label)
        notes.append(f"✅ {label}")
    time.sleep(0.2)
    prog.empty()
    return notes


def create_ticket_from_text(user_text: str, urgency: str, mood: str) -> Ticket:
    category = classify_category(user_text)
    ctx = context_line()
    summary = user_text.strip()
    if ctx:
        summary = f"{summary} | {ctx}"
    t = Ticket(
        ticket_id=new_ticket_id(),
        created_at=now_str(),
        category=category,
        urgency=urgency,
        summary=summary[:400],
        status="Open",
        mood=mood,
    )
    ticket_insert(t)
    metric_bump("escalated", 1)
    return t


def try_contain(user_text: str) -> Tuple[bool, str]:
    title, score = best_kb_match(user_text)
    if score >= 0.28:
        msg = kb_answer(title) + "\n\nIf that doesn’t work, type **create ticket**."
        return True, msg
    return False, (
        "Tell me:\n"
        "1) What you were trying to do\n"
        "2) Exact error text (copy/paste)\n"
        "3) Urgency (low/med/high)\n\n"
        "Or type **create ticket** and I’ll file it."
    )


