with tab_chat:
    st.markdown("<div class='small-muted'>Quick actions</div>", unsafe_allow_html=True)
    a1, a2, a3, a4 = st.columns(4)
    quick = [
        ("🔐 Login", "Login"),
        ("🛡️ VPN", "VPN"),
        ("📶 Wi‑Fi", "Wi‑Fi"),
        ("🧩 Software", "Software"),
    ]
    clicked = None
    for (label, kind), col in zip(quick, [a1, a2, a3, a4]):
        if col.button(label, use_container_width=True):
            clicked = kind

    if clicked:
        st.session_state.messages.append({"role": "user", "content": f"[Quick check] {clicked}"})
        with st.chat_message("assistant"):
            st.markdown(f"Got it. Running a quick **{clicked}** check…")
            notes = run_quick_check(clicked)
            st.markdown("\n".join(notes))
            if clicked == "VPN":
                st.markdown(kb_answer("VPN not connecting"))
            elif clicked == "Wi‑Fi":
                st.markdown(kb_answer("Wi‑Fi issues"))
            elif clicked == "Login":
                st.markdown(kb_answer("MFA / 2FA trouble") + "\n\n" + kb_answer("Password reset"))
            else:
                st.markdown(kb_answer("Install software"))
            st.markdown("\nIf you’re still blocked, type **create ticket**.")
        metric_bump("contained", 1)
        st.rerun()

    st.divider()

    # Render history
    for m in st.session_state.messages:
        with st.chat_message(m["role"]):
            st.markdown(m["content"])

    # Chat input
    user_text = st.chat_input("Describe your issue… (e.g., “VPN error 809 on Windows”)")
    if user_text:
        st.session_state.messages.append({"role": "user", "content": user_text})

        lower = user_text.lower().strip()

        # Ticket creation flow (simple command)
        if lower.startswith("create ticket"):
            with st.chat_message("assistant"):
                st.markdown("Let’s file it—two quick picks:")
                urgency = st.radio("Urgency", ["low", "med", "high"], horizontal=True, index=1)
                mood = st.selectbox("How’s your day going?", ["Calm 😌", "Focused 🎯", "Stressed 😵‍💫", "On fire 🔥"], index=1)
                summary = st.text_area("One-line summary (optional)", placeholder="If blank, I’ll use your last message.")
                confirm = st.button("🎫 Create ticket", type="primary", use_container_width=True)

            if confirm:
                # Use last non-command message if summary blank
                last_issue = ""
                for msg in reversed(st.session_state.messages):
                    if msg["role"] == "user" and not msg["content"].lower().strip().startswith("create ticket"):
                        last_issue = msg["content"]
                        break
                seed = summary.strip() if summary.strip() else (last_issue or "General help needed")
                t = create_ticket_from_text(seed, urgency=urgency, mood=mood)
                st.session_state.messages.append(
                    {
                        "role": "assistant",
                        "content": (
                            f"Ticket created: **{t.ticket_id}** 🎉\n\n"
                            f"- Category: **{t.category}**\n"
                            f"- Urgency: **{t.urgency}**\n"
                            f"- Status: **{t.status}**\n\n"
                            "Want to add the exact error text or a screenshot description?"
                        ),
                    }
                )
                st.balloons()
                st.rerun()

        else:
            assistant_typing()
            contained, reply = try_contain(user_text)
            st.session_state.messages.append({"role": "assistant", "content": reply})
            if contained:
                metric_bump("contained", 1)
            st.rerun()
